    private static readonly int[]    Roots     = [0, 15, 30, 45, 60, 75, 90, 105, 120, 135, 150, 165, 180, 195, 210, 225, 240, 255, 270, 285, 300, 315, 330, 345, 358, 373, 388, 401, 416, 431, 446, 461, 476, 489, 504, 519, 534, 547, 562, 575, 590, 605, 618, 631, 646, 661, 676, 691, 704, 715];

    // Left[node] == -1 means leaf node
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    private static double Eval(int node, ReadOnlySpan<double> f)
    {
        while (true)
        {
            if (Left[node] < 0)
                return Value[node];
            double v = f[Feature[node]];
            if (double.IsNaN(v))
                node = Missing[node];
            else if ((float)v < Threshold[node])
                node = Left[node];
            else
                node = Right[node];
        }
    }

    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    public static double Predict(ReadOnlySpan<double> f)
    {
        double s = BaseScore;
        for (int i = 0; i < TreeCount; i++)
            s += Eval(Roots[i], f);
        return s;
    }
